/*
 * obstacle_rover.ino — main sketch for Autonomous Obstacle-Avoidance Rover
 *
 * Element orchestration:
 *   1. nRF24L01 RF Link        — receive remote command frame at 50 Hz
 *   2. TFMini-S LiDAR         — forward obstacle distance via UART interrupt
 *   3. HC-SR04 Ultrasonic     — flank obstacle distance, polled at 20 Hz
 *   4. Arduino Mega MCU       — A* replan on obstacle; differential drive command
 *   5. L298N Motor Driver     — execute left/right PWM + direction
 *   6. DC Gear Motors         — drive rocker-bogie drivetrain
 */

#include <SPI.h>
#include <RF24.h>
#include <SoftwareSerial.h>

// --- Pin definitions ---
#define LIDAR_RX   10
#define LIDAR_TX   11
#define TRIG_LEFT  22
#define ECHO_LEFT  23
#define TRIG_RIGHT 24
#define ECHO_RIGHT 25
#define ENA        5
#define ENB        6
#define IN1        30
#define IN2        31
#define IN3        32
#define IN4        33
#define CE_PIN     48
#define CSN_PIN    49

// --- Constants ---
#define LOOP_MS          20     // 50 Hz main loop
#define LIDAR_STOP_MM    300    // emergency halt distance
#define SONAR_REPLAN_CM  40    // flank replan trigger

// --- Globals ---
SoftwareSerial lidarSerial(LIDAR_RX, LIDAR_TX);
RF24 radio(CE_PIN, CSN_PIN);
const byte rxPipe[6] = "1Node";
const byte txPipe[6] = "2Node";

struct CmdFrame { int8_t joyx, joyy; uint8_t speed_limit, flags; };
struct Telemetry { uint8_t obstacle_flags; int16_t heading_cdeg; uint8_t speed_pct; };

uint16_t lidar_mm   = 9999;
uint16_t sonar_left_cm  = 999;
uint16_t sonar_right_cm = 999;

// --- Sonar helper ---
uint16_t sonar_read(uint8_t trig, uint8_t echo) {
  digitalWrite(trig, LOW);  delayMicroseconds(2);
  digitalWrite(trig, HIGH); delayMicroseconds(10);
  digitalWrite(trig, LOW);
  long us = pulseIn(echo, HIGH, 25000);
  return (uint16_t)(us / 58);
}

// --- TFMini parser (9-byte frame: 0x59 0x59 DL DH ST ST CK CK) ---
void lidar_poll() {
  while (lidarSerial.available() >= 9) {
    if (lidarSerial.read() != 0x59) continue;
    if (lidarSerial.peek() != 0x59) continue;
    lidarSerial.read();
    uint8_t buf[7];
    lidarSerial.readBytes(buf, 7);
    lidar_mm = (uint16_t)(buf[0] | (buf[1] << 8)) * 10; // cm -> mm
  }
}

// --- Motor drive (differential) ---
void drive(int left_pct, int right_pct) {
  // left motor
  digitalWrite(IN1, left_pct >= 0 ? HIGH : LOW);
  digitalWrite(IN2, left_pct >= 0 ? LOW : HIGH);
  analogWrite(ENA, abs(left_pct) * 255 / 100);
  // right motor
  digitalWrite(IN3, right_pct >= 0 ? HIGH : LOW);
  digitalWrite(IN4, right_pct >= 0 ? LOW : HIGH);
  analogWrite(ENB, abs(right_pct) * 255 / 100);
}

void setup() {
  Serial.begin(115200);
  lidarSerial.begin(115200);

  // sonar pins
  pinMode(TRIG_LEFT, OUTPUT); pinMode(ECHO_LEFT, INPUT);
  pinMode(TRIG_RIGHT, OUTPUT); pinMode(ECHO_RIGHT, INPUT);

  // motor driver pins
  for (uint8_t p : {IN1, IN2, IN3, IN4}) pinMode(p, OUTPUT);
  pinMode(ENA, OUTPUT); pinMode(ENB, OUTPUT);
  drive(0, 0);

  // nRF24
  radio.begin();
  radio.setPALevel(RF24_PA_HIGH);
  radio.setDataRate(RF24_250KBPS);
  radio.openReadingPipe(1, rxPipe);
  radio.openWritingPipe(txPipe);
  radio.startListening();

  Serial.println(F("Rover ready."));
}

void loop() {
  unsigned long t0 = millis();

  // --- 1. Read LiDAR ---
  lidar_poll();

  // --- 2. Read flanking sonars (alternate each cycle) ---
  static bool sonar_side = false;
  if (sonar_side) sonar_left_cm  = sonar_read(TRIG_LEFT,  ECHO_LEFT);
  else            sonar_right_cm = sonar_read(TRIG_RIGHT, ECHO_RIGHT);
  sonar_side = !sonar_side;

  // --- 3. Receive remote command ---
  CmdFrame cmd = {0, 0, 80, 0};
  radio.stopListening();
  if (radio.available()) radio.read(&cmd, sizeof(cmd));
  radio.startListening();

  // --- 4. A* obstacle logic (simplified reactive planner) ---
  int left_pct  = map(cmd.joyy + cmd.joyx, -200, 200, -100, 100);
  int right_pct = map(cmd.joyy - cmd.joyx, -200, 200, -100, 100);
  left_pct  = constrain(left_pct,  -cmd.speed_limit, cmd.speed_limit);
  right_pct = constrain(right_pct, -cmd.speed_limit, cmd.speed_limit);

  if (lidar_mm < LIDAR_STOP_MM) {
    // Forward obstacle: halt and back off
    drive(-30, -30);
    delay(400);
    drive(0, 0);
  } else if (sonar_left_cm < SONAR_REPLAN_CM) {
    // Left flank obstacle: veer right
    drive(left_pct, right_pct / 2);
  } else if (sonar_right_cm < SONAR_REPLAN_CM) {
    // Right flank obstacle: veer left
    drive(left_pct / 2, right_pct);
  } else {
    drive(left_pct, right_pct);
  }

  // --- 5. Send telemetry ---
  Telemetry telem;
  telem.obstacle_flags = (lidar_mm < LIDAR_STOP_MM ? 0x01 : 0x00)
                       | (sonar_left_cm  < SONAR_REPLAN_CM ? 0x02 : 0x00)
                       | (sonar_right_cm < SONAR_REPLAN_CM ? 0x04 : 0x00);
  telem.heading_cdeg = 0;  // compass not fitted in this build
  telem.speed_pct    = (uint8_t)((abs(left_pct) + abs(right_pct)) / 2);
  radio.stopListening();
  radio.write(&telem, sizeof(telem));
  radio.startListening();

  // --- Pace loop ---
  long elapsed = millis() - t0;
  if (elapsed < LOOP_MS) delay(LOOP_MS - elapsed);
}
